parameters.functionCode:
// Parse the AI-generated content into structured format
const response = $input.item.json.response;

// Extract sections using regex
const instagramMatch = response.match(/INSTAGRAM:[\s\S]*?(?=FACEBOOK:|$)/);
const facebookMatch = response.match(/FACEBOOK:[\s\S]*?(?=TIKTOK:|$)/);
const tiktokMatch = response.match(/TIKTOK:[\s\S]*?(?=PINTEREST:|$)/);
const pinterestMatch = response.match(/PINTEREST:[\s\S]*?$/);

// Clean up extracted content
function cleanSection(text) {
  return text ? text.replace(/^[A-Z]+:\s*/g, '').trim() : '';
}

const instagram = cleanSection(instagramMatch ? instagramMatch[0] : '');
const facebook = cleanSection(facebookMatch ? facebookMatch[0] : '');
const tiktok = cleanSection(tiktokMatch ? tiktokMatch[0] : '');
const pinterest = cleanSection(pinterestMatch ? pinterestMatch[0] : '');

// Get product data
const product = $node['Shopify - Get Product'].json;
const vision = $node['Moondream - Analyze Image'].json;

return {
  json: {
    product_id: product.id,
    product_title: product.title,
    product_price: product.variants[0].price,
    product_url: `https://shorettesbaitandtackle.myshopify.com/products/${product.handle}`,
    image_url: product.images[0].src,
    vision_analysis: vision.description,

    social_content: {
      instagram: {
        caption: instagram,
        character_count: instagram.length
      },
      facebook: {
        post: facebook,
        character_count: facebook.length
      },
      tiktok: {
        hook: tiktok,
        full_script: tiktok  // Can expand later
      },
      pinterest: {
        description: pinterest,
        character_count: pinterest.length
      }
    },

    created_at: new Date().toISOString(),
    created_by: 'Marina AI'
  }
};

